SELECT * FROM patient WHERE deleted = 0
AND ( name LIKE CONCAT('%', #{keyword}, '%') OR phone LIKE CONCAT('%', #{keyword}, '%') OR id_card LIKE CONCAT('%', #{keyword}, '%') OR patient_no LIKE CONCAT('%', #{keyword}, '%') )
AND create_time >= #{startTime}
AND create_time <= #{endTime}
